// WATI webhook payload format
// Only process inbound messages from contacts (owner: false)
// and only actual message events (not status updates)

const body = $input.first().json.body || $input.first().json;

// Filter: only process messages FROM the contact, not from the agent
if (body.owner === true) return [];

// Filter: only process 'message' events (WATI also sends status events)
if (body.eventType && body.eventType !== 'message') return [];

// Extract fields from WATI payload
const waId = body.waId || body.messageContact?.waId || '';
const contactName = body.senderName
  || body.messageContact?.name
  || body.messageContact?.firstName
  || 'Guest';

// Message text — handle text and interactive (button/list) replies
let messageText = '';
if (body.type === 'text') {
  messageText = body.text || '';
} else if (body.type === 'interactive') {
  messageText = body.interactive?.buttonReply?.title
    || body.interactive?.listReply?.title
    || '[interactive message]';
} else {
  messageText = `[${body.type || 'unknown'} message]`;
}

if (!waId || !messageText) return [];

return [{ json: {
  waId,
  fromPhone: waId,
  messageText,
  messageType: body.type || 'text',
  contactName,
  conversationId: body.conversationId || null,
  watiMessageId: body.id || null,
  timestamp: body.timestamp || Date.now()
} }];

// HK Business Hours: Mon–Sat 09:00–19:00 HKT (UTC+8)
const now = new Date();
const hkOffset = 8 * 60;
const utcMinutes = now.getUTCHours() * 60 + now.getUTCMinutes();
const hkMinutes = (utcMinutes + hkOffset) % (24 * 60);
const hkDay = new Date(now.getTime() + hkOffset * 60000).getUTCDay();
// 0=Sun, 1=Mon, 6=Sat

const isWeekday = hkDay >= 1 && hkDay <= 6;
const isOpenHours = hkMinutes >= 540 && hkMinutes < 1140; // 9am–7pm
const isBusinessHours = isWeekday && isOpenHours;

const hkHH = Math.floor(hkMinutes/60).toString().padStart(2,'0');
const hkMM = (hkMinutes%60).toString().padStart(2,'0');

return [{ json: {
  ...$input.first().json,
  isBusinessHours,
  hkTime: `${hkHH}:${hkMM}`,
  hkDay
} }];

const contactData = $input.first().json;
const contacts = contactData.contacts || [];
const existingContact = contacts[0] || null;

let conversationHistory = [];
if (existingContact) {
  const historyField = existingContact.customFields?.find(f => f.key === 'scalar_wa_history');
  if (historyField?.value) {
    try { conversationHistory = JSON.parse(historyField.value).slice(-12); } catch(e) {}
  }
}

const msgData = $('Extract Message Data').first().json;

return [{ json: {
  ...msgData,
  existingContact,
  ghlContactId: existingContact?.id || null,
  conversationHistory,
  resolvedName: existingContact?.firstName || msgData.contactName
} }];

const aiRaw = $input.first().json.choices[0].message.content;

let bookingData = null;
const bookingMatch = aiRaw.match(/\[BOOKING_INTENT\]([\s\S]*?)\[\/BOOKING_INTENT\]/);
if (bookingMatch) {
  try { bookingData = JSON.parse(bookingMatch[1]); } catch(e) {}
}

const cleanResponse = aiRaw.replace(/\[BOOKING_INTENT\][\s\S]*?\[\/BOOKING_INTENT\]/g, '').trim();

const prevHistory = $('Build Conversation Context').first().json.conversationHistory || [];
const updatedHistory = [
  ...prevHistory,
  { role: 'user', content: $('Build Conversation Context').first().json.messageText },
  { role: 'assistant', content: cleanResponse }
].slice(-20);

const ctx = $('Build Conversation Context').first().json;

return [{ json: {
  ...ctx,
  aiResponse: cleanResponse,
  bookingData,
  hasBookingIntent: !!bookingData,
  updatedHistoryJson: JSON.stringify(updatedHistory)
} }];
